import { z } from 'zod';
import { mapAlbum, mapArtist, mapPlaylist, mapSong, parseImageUrls, } from '../../common-mapper.js';
import { SaavnGetDetailsSchema } from './schema.ops.js';
export const SaavnGetDetailsMapper = {
    album: (data) => {
        return mapAlbum(data);
    },
    artist: (data) => {
        return mapArtist(data);
    },
    playlist: (data) => {
        return mapPlaylist(data);
    },
    songs: (data) => {
        return {
            songs: data.songs.map(mapSong),
        };
    },
    topAlbumsOfTheYear: (data) => {
        return data.map(mapAlbum);
    },
    topSearches: (data) => {
        return data.map((item) => {
            const baseItem = {
                id: item.id,
                title: item.title,
                subtitle: item.subtitle,
                url: item.perma_url,
                images: parseImageUrls(item.image),
                type: item.type,
            };
            if (item.type === 'album') {
                return {
                    ...baseItem,
                    type: 'album',
                    album: item.more_info?.album,
                };
            }
            else if (item.type === 'artist') {
                return {
                    ...baseItem,
                    type: 'artist',
                };
            }
            else if (item.type === 'song') {
                return {
                    ...baseItem,
                    type: 'song',
                    album: item.more_info?.album,
                };
            }
            return baseItem;
        });
    },
};
